import { createAsyncThunk } from "@reduxjs/toolkit";

export const fetchGames = createAsyncThunk(
  "games/fetchGames",
  async () => {
    const res = await fetch("http://localhost:8000/api/games/");
    if (!res.ok) throw new Error("Ошибка загрузки игр");
    return await res.json();
  }
);

export const addGameToCart = createAsyncThunk(
  "cart/addGameToCart",
  async (id, { rejectWithValue }) => {
    try {
      const res = await fetch(`http://localhost:8000/api/cart/add/${id}/`, {
        method: "POST",
      });

      if (!res.ok) throw new Error("Ошибка добавления в корзину");

      return id;
    } catch (err) {
      return rejectWithValue(err.message);
    }
  }
);
